        amendment_number="C409melb",
        title="VISION",
        content='<p>The vision for the City is to be a <strong>bold, inspirational and sustainable</strong> city.&nbsp;</p><p>To achieve this vision, there are six high level goals for the City of Melbourne to be:</p><ul style="list-style-type:square;"><li>A city for people.</li><li>A creative city.</li><li>A prosperous city.</li><li>A city of knowledge.</li><li>An eco-city.</li><li>A connected city.</li></ul>',
